  1→using System;
  2→using System.Diagnostics;
  3→using System.Drawing;
  4→using System.IO;
  5→using System.Linq;
  6→using System.Windows.Forms;
  7→
  8→namespace Updater_Agent
  9→{
 10→    /// <summary>트레이 아이콘 기반 Application Context + 프로세스 감시</summary>
 11→    public class AgentContext : ApplicationContext
 12→    {
 13→        private readonly NotifyIcon _trayIcon;
 14→        private readonly ContextMenuStrip _menu;
 15→        private readonly ToolStripMenuItem _statusItem;
 16→        private readonly ToolStripMenuItem _processItem;
 17→        private readonly UpdateListener _listener;
 18→        private readonly AgentConfig _config;
 19→        private readonly string _logPath;
 20→        private readonly System.Threading.Timer? _monitorTimer;
 21→        private readonly string _exeFolder;
 22→
 23→        public AgentContext()
 24→        {
 25→            _config = AgentConfig.Load();
 26→            _logPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "updater_agent.log");
 27→
 28→            // exe 폴더 결정 (비어있으면 Agent 실행 폴더)
 29→            _exeFolder = string.IsNullOrEmpty(_config.ExeFolder)
 30→                ? AppDomain.CurrentDomain.BaseDirectory
 31→                : _config.ExeFolder;
 32→
 33→            // 트레이 메뉴 구성
 34→            _statusItem = new ToolStripMenuItem("상태: 초기화 중") { Enabled = false };
 35→            _processItem = new ToolStripMenuItem("프로세스: -") { Enabled = false };
 36→
 37→            _menu = new ContextMenuStrip();
 38→            _menu.Items.Add(_statusItem);
 39→            _menu.Items.Add(_processItem);
 40→            _menu.Items.Add(new ToolStripSeparator());
 41→            _menu.Items.Add("로그 열기", null, (s, e) => OpenLog());
 42→            _menu.Items.Add("설정 열기", null, (s, e) => OpenConfig());
 43→            _menu.Items.Add(new ToolStripSeparator());
 44→            _menu.Items.Add("종료", null, (s, e) => ExitThread());
 45→
 46→            // 트레이 아이콘
 47→            _trayIcon = new NotifyIcon
 48→            {
 49→                Icon = SystemIcons.Application,
 50→                Text = "Updater Agent",
 51→                ContextMenuStrip = _menu,
 52→                Visible = true
 53→            };
 54→
 55→            // 리스너 시작
 56→            _listener = new UpdateListener(_config);
 57→            _listener.OnLog += OnLogMessage;
 58→            _listener.OnStatusChanged += OnStatusUpdate;
 59→
 60→            try
 61→            {
 62→                _listener.Start();
 63→                _trayIcon.ShowBalloonTip(2000, "Updater Agent",
 64→                    $"수신 대기 중 (Port: {_config.Port})", ToolTipIcon.Info);
 65→            }
 66→            catch (Exception ex)
 67→            {
 68→                _trayIcon.ShowBalloonTip(3000, "Updater Agent",
 69→                    $"시작 실패: {ex.Message}", ToolTipIcon.Error);
 70→                WriteLog($"시작 실패: {ex.Message}");
 71→            }
 72→
 73→            // 프로세스 감시 타이머 시작
 74→            if (_config.MonitorIntervalSec > 0 && !string.IsNullOrEmpty(_config.TargetProcessPattern))
 75→            {
 76→                int intervalMs = _config.MonitorIntervalSec * 1000;
 77→                // 최초 5초 후 시작 (Agent 기동 직후 바로 실행하지 않음)
 78→                _monitorTimer = new System.Threading.Timer(MonitorCallback, null, 5000, intervalMs);
 79→                WriteLog($"프로세스 감시 시작 (패턴: {_config.TargetProcessPattern}, 주기: {_config.MonitorIntervalSec}초)");
 80→            }
 81→        }
 82→
 83→        /// <summary>프로세스 감시 콜백: 대상 프로세스가 없으면 자동 실행</summary>
 84→        private void MonitorCallback(object? state)
 85→        {
 86→            try
 87→            {
 88→                // 업데이트 중이면 감시 건너뜀
 89→                if (_listener.IsUpdating) return;
 90→
 91→                // 대상 프로세스 실행 중인지 확인
 92→                bool isRunning = IsTargetProcessRunning(out string? processName);
 93→
 94→                // 트레이 메뉴 프로세스 상태 업데이트
 95→                UpdateProcessStatus(isRunning, processName);
 96→
 97→                if (isRunning) return;
 98→
 99→                // 대상 exe 찾기 (패턴 매칭, 가장 최신 파일)
100→                string? exePath = FindTargetExe();
101→                if (exePath == null)
102→                {
103→                    WriteLog($"자동 실행 실패: {_config.TargetProcessPattern}*.exe 파일 없음 ({_exeFolder})");
104→                    return;
105→                }
106→
107→                // 실행
108→                WriteLog($"프로세스 미감지 → 자동 실행: {Path.GetFileName(exePath)}");
109→                Process.Start(new ProcessStartInfo
110→                {
111→                    FileName = exePath,
112→                    WorkingDirectory = _exeFolder,
113→                    UseShellExecute = true
114→                });
115→            }
116→            catch (Exception ex)
117→            {
118→                WriteLog($"감시 오류: {ex.Message}");
119→            }
120→        }
121→
122→        /// <summary>대상 프로세스가 실행 중인지 확인</summary>
123→        private bool IsTargetProcessRunning(out string? processName)
124→        {
125→            processName = null;
126→            var processes = Process.GetProcesses();
127→            try
128→            {
129→                foreach (var proc in processes)
130→                {
131→                    try
132→                    {
133→                        if (proc.ProcessName.StartsWith(_config.TargetProcessPattern,
134→                            StringComparison.OrdinalIgnoreCase))
135→                        {
136→                            processName = proc.ProcessName;
137→                            return true;
138→                        }
139→                    }
140→                    catch { }
141→                    finally { proc.Dispose(); }
142→                }
143→            }
144→            catch { }
145→            return false;
146→        }
147→
148→        /// <summary>폴더에서 패턴 매칭되는 최신 exe 찾기</summary>
149→        private string? FindTargetExe()
150→        {
151→            try
152→            {
153→                if (!Directory.Exists(_exeFolder)) return null;
154→
155→                var dir = new DirectoryInfo(_exeFolder);
156→                var exeFile = dir.GetFiles($"{_config.TargetProcessPattern}*.exe")
157→                    .Where(f => !f.Name.Equals("Updater_Agent.exe", StringComparison.OrdinalIgnoreCase))
158→                    .OrderByDescending(f => f.LastWriteTime)
159→                    .FirstOrDefault();
160→
161→                return exeFile?.FullName;
162→            }
163→            catch
164→            {
165→                return null;
166→            }
167→        }
168→
169→        /// <summary>트레이 메뉴의 프로세스 상태 업데이트</summary>
170→        private void UpdateProcessStatus(bool running, string? processName)
171→        {
172→            try
173→            {
174→                string text = running
175→                    ? $"프로세스: {processName} (실행 중)"
176→                    : "프로세스: 미실행";
177→
178→                if (_menu.InvokeRequired)
179→                    _menu.Invoke(() => _processItem.Text = text);
180→                else
181→                    _processItem.Text = text;
182→            }
183→            catch { }
184→        }
185→
186→        private void OnLogMessage(string msg)
187→        {
188→            WriteLog(msg);
189→        }
190→
191→        private void OnStatusUpdate(string status)
192→        {
193→            try
194→            {
195→                if (_menu.InvokeRequired)
196→                    _menu.Invoke(() => UpdateStatus(status));
197→                else
198→                    UpdateStatus(status);
199→            }
200→            catch { }
201→        }
202→
203→        private void UpdateStatus(string status)
204→        {
205→            _statusItem.Text = $"상태: {status}";
206→            _trayIcon.Text = $"Updater Agent - {status}";
207→        }
208→
209→        private void WriteLog(string msg)
210→        {
211→            try
212→            {
213→                File.AppendAllText(_logPath,
214→                    $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {msg}\r\n");
215→            }
216→            catch { }
217→        }
218→
219→        private void OpenLog()
220→        {
221→            try
222→            {
223→                if (File.Exists(_logPath))
224→                    Process.Start("notepad.exe", _logPath);
225→                else
226→                    MessageBox.Show("로그 파일이 아직 없습니다.", "Updater Agent");
227→            }
228→            catch { }
229→        }
230→
231→        private void OpenConfig()
232→        {
233→            try
234→            {
235→                var configPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "agent_config.json");
236→                Process.Start("notepad.exe", configPath);
237→            }
238→            catch { }
239→        }
240→
241→        protected override void ExitThreadCore()
242→        {
243→            _monitorTimer?.Dispose();
244→            _listener.Stop();
245→            _trayIcon.Visible = false;
246→            _trayIcon.Dispose();
247→            base.ExitThreadCore();
248→        }
249→    }
250→}
251→

  1→using System;
  2→using System.Drawing;
  3→using System.IO;
  4→using System.Linq;
  5→using System.Threading.Tasks;
  6→using System.Windows.Forms;
  7→
  8→namespace Updater_Server
  9→{
 10→    public partial class FrmMain : Form
 11→    {
 12→        private ServerConfig _config;
 13→        private bool _sending = false;
 14→
 15→        public FrmMain()
 16→        {
 17→            InitializeComponent();
 18→            _config = ServerConfig.Load();
 19→            LoadStations();
 20→        }
 21→
 22→        /// <summary>설정 파일의 스테이션 목록을 그리드에 로드</summary>
 23→        private void LoadStations()
 24→        {
 25→            dgvStations.Rows.Clear();
 26→            foreach (var st in _config.Stations)
 27→            {
 28→                // exe 경로가 있으면 파일명만 표시, 없으면 "(클릭하여 선택)"
 29→                string displayName = string.IsNullOrEmpty(st.ExePath)
 30→                    ? "(클릭하여 선택)"
 31→                    : Path.GetFileName(st.ExePath);
 32→
 33→                bool hasExe = !string.IsNullOrEmpty(st.ExePath) && File.Exists(st.ExePath);
 34→
 35→                int idx = dgvStations.Rows.Add(hasExe, st.Name, st.IP, st.Port, displayName, "대기");
 36→                dgvStations.Rows[idx].Tag = st;
 37→
 38→                // exe 파일이 없거나 경로가 유효하지 않으면 빨간색
 39→                if (!string.IsNullOrEmpty(st.ExePath) && !File.Exists(st.ExePath))
 40→                {
 41→                    dgvStations.Rows[idx].Cells["colExePath"].Style.ForeColor = Color.Red;
 42→                    dgvStations.Rows[idx].Cells["colStatus"].Value = "파일 없음";
 43→                    dgvStations.Rows[idx].Cells["colStatus"].Style.ForeColor = Color.Red;
 44→                }
 45→            }
 46→        }
 47→
 48→        /// <summary>그리드 셀 클릭 - exe 컬럼이면 파일 다이얼로그</summary>
 49→        private void dgvStations_CellClick(object sender, DataGridViewCellEventArgs e)
 50→        {
 51→            if (e.RowIndex < 0) return;
 52→            if (e.ColumnIndex != dgvStations.Columns["colExePath"].Index) return;
 53→
 54→            var row = dgvStations.Rows[e.RowIndex];
 55→            var station = row.Tag as StationInfo;
 56→            if (station == null) return;
 57→
 58→            // 파일 다이얼로그
 59→            using var dlg = new OpenFileDialog
 60→            {
 61→                Title = $"{station.Name} - 실행파일 선택",
 62→                Filter = "실행파일 (*.exe)|*.exe|모든 파일 (*.*)|*.*"
 63→            };
 64→
 65→            // 기존 경로가 있으면 해당 폴더로
 66→            if (!string.IsNullOrEmpty(station.ExePath) && Directory.Exists(Path.GetDirectoryName(station.ExePath)))
 67→                dlg.InitialDirectory = Path.GetDirectoryName(station.ExePath)!;
 68→
 69→            if (dlg.ShowDialog() != DialogResult.OK) return;
 70→
 71→            // 설정 업데이트 + 저장
 72→            station.ExePath = dlg.FileName;
 73→            _config.Save();
 74→
 75→            // 그리드 업데이트
 76→            row.Cells["colExePath"].Value = Path.GetFileName(dlg.FileName);
 77→            row.Cells["colExePath"].Style.ForeColor = Color.Black;
 78→            row.Cells["colSelect"].Value = true;
 79→            row.Cells["colStatus"].Value = "대기";
 80→            row.Cells["colStatus"].Style.ForeColor = Color.Black;
 81→
 82→            AppendLog($"[{station.Name}] exe 설정: {dlg.FileName}");
 83→        }
 84→
 85→        /// <summary>전체 선택/해제 토글</summary>
 86→        private void btnSelectAll_Click(object sender, EventArgs e)
 87→        {
 88→            bool allChecked = dgvStations.Rows.Cast<DataGridViewRow>()
 89→                .All(r => Convert.ToBoolean(r.Cells["colSelect"].Value));
 90→
 91→            foreach (DataGridViewRow row in dgvStations.Rows)
 92→                row.Cells["colSelect"].Value = !allChecked;
 93→
 94→            btnSelectAll.Text = allChecked ? "전체 선택" : "전체 해제";
 95→        }
 96→
 97→        /// <summary>선택된 스테이션에 전송</summary>
 98→        private async void btnSend_Click(object sender, EventArgs e)
 99→        {
100→            if (_sending)
101→            {
102→                MessageBox.Show("전송 중입니다. 완료 후 다시 시도하세요.", "알림",
103→                    MessageBoxButtons.OK, MessageBoxIcon.Information);
104→                return;
105→            }
106→
107→            // 선택된 스테이션 중 exe 파일이 유효한 것만 필터
108→            var selectedRows = dgvStations.Rows.Cast<DataGridViewRow>()
109→                .Where(r => Convert.ToBoolean(r.Cells["colSelect"].Value))
110→                .ToList();
111→
112→            if (selectedRows.Count == 0)
113→            {
114→                MessageBox.Show("전송 대상 스테이션을 선택하세요.", "알림",
115→                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
116→                return;
117→            }
118→
119→            // exe 파일 유효성 검사
120→            var invalidRows = selectedRows.Where(r =>
121→            {
122→                var st = r.Tag as StationInfo;
123→                return st == null || string.IsNullOrEmpty(st.ExePath) || !File.Exists(st.ExePath);
124→            }).ToList();
125→
126→            if (invalidRows.Count > 0)
127→            {
128→                var names = string.Join(", ", invalidRows.Select(r => r.Cells["colName"].Value));
129→                MessageBox.Show($"다음 스테이션의 exe 파일이 지정되지 않았거나 존재하지 않습니다:\n{names}",
130→                    "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
131→                return;
132→            }
133→
134→            // 전송 확인
135→            var stationList = string.Join("\n", selectedRows.Select(r =>
136→            {
137→                var st = r.Tag as StationInfo;
138→                return $"  {st!.Name} → {Path.GetFileName(st.ExePath)}";
139→            }));
140→            var result = MessageBox.Show(
141→                $"다음 스테이션에 전송하시겠습니까?\n\n{stationList}",
142→                "전송 확인", MessageBoxButtons.YesNo, MessageBoxIcon.Question);
143→
144→            if (result != DialogResult.Yes) return;
145→
146→            _sending = true;
147→            btnSend.Enabled = false;
148→            btnSend.Text = "전송 중...";
149→
150→            AppendLog($"=== 전송 시작: {selectedRows.Count}개 스테이션 ===");
151→
152→            // 선택된 스테이션에 병렬 전송
153→            var tasks = selectedRows.Select(row => SendToStation(row)).ToArray();
154→            await Task.WhenAll(tasks);
155→
156→            // 결과 요약
157→            int success = selectedRows.Count(r => r.Cells["colStatus"].Value?.ToString() == "완료");
158→            int fail = selectedRows.Count - success;
159→            AppendLog($"=== 전송 완료: 성공 {success}, 실패 {fail} ===");
160→
161→            _sending = false;
162→            btnSend.Enabled = true;
163→            btnSend.Text = "전송";
164→        }
165→
166→        /// <summary>단일 스테이션에 파일 전송</summary>
167→        private async Task SendToStation(DataGridViewRow row)
168→        {
169→            var station = row.Tag as StationInfo;
170→            if (station == null) return;
171→
172→            SetRowStatus(row, "전송 중...", Color.Orange);
173→            AppendLog($"[{station.Name}] {station.IP}:{station.Port} → {Path.GetFileName(station.ExePath)}");
174→
175→            var result = await FileSender.SendFileAsync(station.IP, station.Port, station.ExePath,
176→                (sent, total) =>
177→                {
178→                    int pct = (int)(sent * 100 / total);
179→                    SetRowStatus(row, $"전송 중... {pct}%", Color.Orange);
180→                });
181→
182→            if (result.Success)
183→            {
184→                SetRowStatus(row, "완료", Color.Green);
185→                AppendLog($"[{station.Name}] 성공: {result.Message}");
186→            }
187→            else
188→            {
189→                SetRowStatus(row, $"실패: {result.Message}", Color.Red);
190→                AppendLog($"[{station.Name}] 실패: {result.Message}");
191→            }
192→        }
193→
194→        /// <summary>그리드 행 상태 업데이트 (UI 스레드 안전)</summary>
195→        private void SetRowStatus(DataGridViewRow row, string status, Color color)
196→        {
197→            if (dgvStations.InvokeRequired)
198→            {
199→                dgvStations.Invoke(() => SetRowStatus(row, status, color));
200→                return;
201→            }
202→            row.Cells["colStatus"].Value = status;
203→            row.Cells["colStatus"].Style.ForeColor = color;
204→        }
205→
206→        /// <summary>로그 추가 (UI 스레드 안전)</summary>
207→        private void AppendLog(string msg)
208→        {
209→            if (txtLog.InvokeRequired)
210→            {
211→                txtLog.Invoke(() => AppendLog(msg));
212→                return;
213→            }
214→            txtLog.AppendText($"[{DateTime.Now:HH:mm:ss}] {msg}\r\n");
215→        }
216→    }
217→}
