 6→namespace Updater_Agent
 7→{
 8→    static class Program
 9→    {
10→        [STAThread]
11→        static void Main()
12→        {
13→            // 전역 예외 핸들러
14→            Application.ThreadException += (s, e) => LogCrash(e.Exception);
15→            AppDomain.CurrentDomain.UnhandledException += (s, e) => LogCrash((Exception)e.ExceptionObject);
16→
17→            // 중복 실행 방지
18→            using var mutex = new Mutex(true, "Updater_Agent", out bool created);
19→            if (!created)
20→            {
21→                MessageBox.Show("이미 실행 중입니다.", "Updater Agent",
22→                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
23→                return;
24→            }
25→
26→            Application.EnableVisualStyles();
27→            Application.SetCompatibleTextRenderingDefault(false);
28→            Application.Run(new AgentContext());
29→        }
30→
31→        static void LogCrash(Exception ex)
32→        {
33→            try
34→            {
35→                var path = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "crash.log");
36→                var msg = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {ex.Source}: {ex.Message}\r\n{ex.StackTrace}\r\n\r\n";
37→                File.AppendAllText(path, msg);
38→            }
39→            catch { }
40→        }
41→    }
42→}
