  1→using System;
  2→using System.Diagnostics;
  3→using System.Drawing;
  4→using System.IO;
  5→using System.Linq;
  6→using System.Windows.Forms;
  7→
  8→namespace Updater_Agent
  9→{
 10→    /// <summary>트레이 아이콘 기반 Application Context + 프로세스 감시</summary>
 11→    public class AgentContext : ApplicationContext
 12→    {
 13→        private readonly NotifyIcon _trayIcon;
 14→        private readonly ContextMenuStrip _menu;
 15→        private readonly ToolStripMenuItem _statusItem;
 16→        private readonly ToolStripMenuItem _processItem;
 17→        private readonly UpdateListener _listener;
 18→        private readonly AgentConfig _config;
 19→        private readonly string _logPath;
 20→        private readonly System.Threading.Timer? _monitorTimer;
 21→        private readonly string _exeFolder;
 22→
 23→        public AgentContext()
 24→        {
 25→            _config = AgentConfig.Load();
 26→            _logPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "updater_agent.log");
 27→
 28→            // exe 폴더 결정 (비어있으면 Agent 실행 폴더)
 29→            _exeFolder = string.IsNullOrEmpty(_config.ExeFolder)
 30→                ? AppDomain.CurrentDomain.BaseDirectory
 31→                : _config.ExeFolder;
 32→
 33→            // 트레이 메뉴 구성
 34→            _statusItem = new ToolStripMenuItem("상태: 초기화 중") { Enabled = false };
 35→            _processItem = new ToolStripMenuItem("프로세스: -") { Enabled = false };
 36→
 37→            _menu = new ContextMenuStrip();
 38→            _menu.Items.Add(_statusItem);
 39→            _menu.Items.Add(_processItem);
 40→            _menu.Items.Add(new ToolStripSeparator());
 41→            _menu.Items.Add("로그 열기", null, (s, e) => OpenLog());
 42→            _menu.Items.Add("설정 열기", null, (s, e) => OpenConfig());
 43→            _menu.Items.Add(new ToolStripSeparator());
 44→            _menu.Items.Add("종료", null, (s, e) => ExitThread());
 45→
 46→            // 트레이 아이콘
 47→            _trayIcon = new NotifyIcon
 48→            {
 49→                Icon = SystemIcons.Application,
 50→                Text = "Updater Agent",
 51→                ContextMenuStrip = _menu,
 52→                Visible = true
 53→            };
 54→
 55→            // 리스너 시작
 56→            _listener = new UpdateListener(_config);
 57→            _listener.OnLog += OnLogMessage;
 58→            _listener.OnStatusChanged += OnStatusUpdate;
 59→
 60→            try
 61→            {
 62→                _listener.Start();
 63→                _trayIcon.ShowBalloonTip(2000, "Updater Agent",
 64→                    $"수신 대기 중 (Port: {_config.Port})", ToolTipIcon.Info);
 65→            }
 66→            catch (Exception ex)
 67→            {
 68→                _trayIcon.ShowBalloonTip(3000, "Updater Agent",
 69→                    $"시작 실패: {ex.Message}", ToolTipIcon.Error);
 70→                WriteLog($"시작 실패: {ex.Message}");
 71→            }
 72→
 73→            // 프로세스 감시 타이머 시작
 74→            if (_config.MonitorIntervalSec > 0 && !string.IsNullOrEmpty(_config.TargetProcessPattern))
 75→            {
 76→                int intervalMs = _config.MonitorIntervalSec * 1000;
 77→                // 최초 5초 후 시작 (Agent 기동 직후 바로 실행하지 않음)
 78→                _monitorTimer = new System.Threading.Timer(MonitorCallback, null, 5000, intervalMs);
 79→                WriteLog($"프로세스 감시 시작 (패턴: {_config.TargetProcessPattern}, 주기: {_config.MonitorIntervalSec}초)");
 80→            }
 81→        }
 82→
 83→        /// <summary>프로세스 감시 콜백: 대상 프로세스가 없으면 자동 실행</summary>
 84→        private void MonitorCallback(object? state)
 85→        {
 86→            try
 87→            {
 88→                // 업데이트 중이면 감시 건너뜀
 89→                if (_listener.IsUpdating) return;
 90→
 91→                // 대상 프로세스 실행 중인지 확인
 92→                bool isRunning = IsTargetProcessRunning(out string? processName);
 93→
 94→                // 트레이 메뉴 프로세스 상태 업데이트
 95→                UpdateProcessStatus(isRunning, processName);
 96→
 97→                if (isRunning) return;
 98→
 99→                // 대상 exe 찾기 (패턴 매칭, 가장 최신 파일)
100→                string? exePath = FindTargetExe();
101→                if (exePath == null)
102→                {
103→                    WriteLog($"자동 실행 실패: {_config.TargetProcessPattern}*.exe 파일 없음 ({_exeFolder})");
104→                    return;
105→                }
106→
107→                // 실행
108→                WriteLog($"프로세스 미감지 → 자동 실행: {Path.GetFileName(exePath)}");
109→                Process.Start(new ProcessStartInfo
110→                {
111→                    FileName = exePath,
112→                    WorkingDirectory = _exeFolder,
113→                    UseShellExecute = true
114→                });
115→            }
116→            catch (Exception ex)
117→            {
118→                WriteLog($"감시 오류: {ex.Message}");
119→            }
120→        }
121→
122→        /// <summary>대상 프로세스가 실행 중인지 확인</summary>
123→        private bool IsTargetProcessRunning(out string? processName)
124→        {
125→            processName = null;
126→            var processes = Process.GetProcesses();
127→            try
128→            {
129→                foreach (var proc in processes)
130→                {
131→                    try
132→                    {
133→                        if (proc.ProcessName.StartsWith(_config.TargetProcessPattern,
134→                            StringComparison.OrdinalIgnoreCase))
135→                        {
136→                            processName = proc.ProcessName;
137→                            return true;
138→                        }
139→                    }
140→                    catch { }
141→                    finally { proc.Dispose(); }
142→                }
143→            }
144→            catch { }
145→            return false;
146→        }
147→
148→        /// <summary>폴더에서 패턴 매칭되는 최신 exe 찾기</summary>
149→        private string? FindTargetExe()
150→        {
151→            try
152→            {
153→                if (!Directory.Exists(_exeFolder)) return null;
154→
155→                var dir = new DirectoryInfo(_exeFolder);
156→                var exeFile = dir.GetFiles($"{_config.TargetProcessPattern}*.exe")
157→                    .Where(f => !f.Name.Equals("Updater_Agent.exe", StringComparison.OrdinalIgnoreCase))
158→                    .OrderByDescending(f => f.LastWriteTime)
159→                    .FirstOrDefault();
160→
161→                return exeFile?.FullName;
162→            }
163→            catch
164→            {
165→                return null;
166→            }
167→        }
168→
169→        /// <summary>트레이 메뉴의 프로세스 상태 업데이트</summary>
170→        private void UpdateProcessStatus(bool running, string? processName)
171→        {
172→            try
173→            {
174→                string text = running
175→                    ? $"프로세스: {processName} (실행 중)"
176→                    : "프로세스: 미실행";
177→
178→                if (_menu.InvokeRequired)
179→                    _menu.Invoke(() => _processItem.Text = text);
180→                else
181→                    _processItem.Text = text;
182→            }
183→            catch { }
184→        }
185→
186→        private void OnLogMessage(string msg)
187→        {
188→            WriteLog(msg);
189→        }
190→
191→        private void OnStatusUpdate(string status)
192→        {
193→            try
194→            {
195→                if (_menu.InvokeRequired)
196→                    _menu.Invoke(() => UpdateStatus(status));
197→                else
198→                    UpdateStatus(status);
199→            }
200→            catch { }
201→        }
202→
203→        private void UpdateStatus(string status)
204→        {
205→            _statusItem.Text = $"상태: {status}";
206→            _trayIcon.Text = $"Updater Agent - {status}";
207→        }
208→
209→        private void WriteLog(string msg)
210→        {
211→            try
212→            {
213→                File.AppendAllText(_logPath,
214→                    $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {msg}\r\n");
215→            }
216→            catch { }
217→        }
218→
219→        private void OpenLog()
220→        {
221→            try
222→            {
223→                if (File.Exists(_logPath))
224→                    Process.Start("notepad.exe", _logPath);
225→                else
226→                    MessageBox.Show("로그 파일이 아직 없습니다.", "Updater Agent");
227→            }
228→            catch { }
229→        }
230→
231→        private void OpenConfig()
232→        {
233→            try
234→            {
235→                var configPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "agent_config.json");
236→                Process.Start("notepad.exe", configPath);
237→            }
238→            catch { }
239→        }
240→
241→        protected override void ExitThreadCore()
242→        {
243→            _monitorTimer?.Dispose();
244→            _listener.Stop();
245→            _trayIcon.Visible = false;
246→            _trayIcon.Dispose();
247→            base.ExitThreadCore();
248→        }
249→    }
250→}
