  1→using System;
  2→using System.Diagnostics;
  3→using System.IO;
  4→using System.Net;
  5→using System.Net.Sockets;
  6→using System.Text;
  7→using System.Threading;
  8→using System.Threading.Tasks;
  9→
 10→namespace Updater_Agent
 11→{
 12→    public class UpdateListener
 13→    {
 14→        private TcpListener? _listener;
 15→        private CancellationTokenSource? _cts;
 16→        private readonly AgentConfig _config;
 17→
 18→        public event Action<string>? OnLog;
 19→        public event Action<string>? OnStatusChanged;
 20→
 21→        /// <summary>업데이트 진행 중 여부 (감시 타이머에서 참조)</summary>
 22→        public bool IsUpdating { get; private set; }
 23→
 24→        // 프로토콜 매직 바이트
 25→        private static readonly byte[] MAGIC_REQ = Encoding.ASCII.GetBytes("NXUP");
 26→        private static readonly byte[] MAGIC_RES = Encoding.ASCII.GetBytes("NXRS");
 27→
 28→        public UpdateListener(AgentConfig config)
 29→        {
 30→            _config = config;
 31→        }
 32→
 33→        public void Start()
 34→        {
 35→            _cts = new CancellationTokenSource();
 36→            _listener = new TcpListener(IPAddress.Any, _config.Port);
 37→            _listener.Start();
 38→            Log($"수신 대기 시작 (Port: {_config.Port})");
 39→            Log($"대상 프로세스: {_config.TargetProcessPattern}");
 40→            Log($"exe 폴더: {_config.ExeFolder}");
 41→            OnStatusChanged?.Invoke("대기 중");
 42→            Task.Run(() => AcceptLoop(_cts.Token));
 43→        }
 44→
 45→        public void Stop()
 46→        {
 47→            _cts?.Cancel();
 48→            _listener?.Stop();
 49→            Log("수신 대기 중지");
 50→            OnStatusChanged?.Invoke("중지됨");
 51→        }
 52→
 53→        private async Task AcceptLoop(CancellationToken ct)
 54→        {
 55→            while (!ct.IsCancellationRequested)
 56→            {
 57→                try
 58→                {
 59→                    var client = await _listener!.AcceptTcpClientAsync(ct);
 60→                    _ = Task.Run(() => HandleClient(client), ct);
 61→                }
 62→                catch (OperationCanceledException) { break; }
 63→                catch (ObjectDisposedException) { break; }
 64→                catch (Exception ex)
 65→                {
 66→                    Log($"Accept 오류: {ex.Message}");
 67→                }
 68→            }
 69→        }
 70→
 71→        private async Task HandleClient(TcpClient client)
 72→        {
 73→            using (client)
 74→            {
 75→                var stream = client.GetStream();
 76→                stream.ReadTimeout = 60000;  // 파일 전송 시 60초
 77→                stream.WriteTimeout = 10000;
 78→
 79→                try
 80→                {
 81→                    Log($"연결 수신: {client.Client.RemoteEndPoint}");
 82→                    OnStatusChanged?.Invoke("수신 중...");
 83→
 84→                    // 1. 매직 바이트 확인
 85→                    var magic = await ReadExact(stream, 4);
 86→                    if (!magic.AsSpan().SequenceEqual(MAGIC_REQ))
 87→                    {
 88→                        await SendResponse(stream, false, "잘못된 프로토콜");
 89→                        return;
 90→                    }
 91→
 92→                    // 2. 파일명 수신
 93→                    var fnLenBuf = await ReadExact(stream, 4);
 94→                    int fnLen = BitConverter.ToInt32(fnLenBuf, 0);
 95→                    var fnBuf = await ReadExact(stream, fnLen);
 96→                    string fileName = Encoding.UTF8.GetString(fnBuf);
 97→
 98→                    // 3. 파일 크기 수신
 99→                    var sizeBuf = await ReadExact(stream, 8);
100→                    long fileSize = BitConverter.ToInt64(sizeBuf, 0);
101→
102→                    Log($"파일 수신 시작: {fileName} ({fileSize:#,0} bytes)");
103→
104→                    // 4. 파일 데이터 수신 → temp 저장
105→                    string tempPath = Path.Combine(Path.GetTempPath(), $"nxupdate_{Guid.NewGuid()}.tmp");
106→                    using (var fs = File.Create(tempPath))
107→                    {
108→                        long remaining = fileSize;
109→                        var buffer = new byte[65536];
110→                        while (remaining > 0)
111→                        {
112→                            int toRead = (int)Math.Min(buffer.Length, remaining);
113→                            int read = await stream.ReadAsync(buffer, 0, toRead);
114→                            if (read == 0) throw new IOException("연결 끊김");
115→                            await fs.WriteAsync(buffer, 0, read);
116→                            remaining -= read;
117→                        }
118→                    }
119→
120→                    Log("파일 수신 완료, 업데이트 시작...");
121→                    IsUpdating = true;
122→                    OnStatusChanged?.Invoke("업데이트 중...");
123→
124→                    // 5. 대상 프로세스 종료
125→                    KillTargetProcess();
126→
127→                    // 6. exe 교체
128→                    // ExeFolder가 비어있으면 Agent 실행 경로 사용
129→                    string exeFolder = string.IsNullOrEmpty(_config.ExeFolder)
130→                        ? AppDomain.CurrentDomain.BaseDirectory
131→                        : _config.ExeFolder;
132→
133→                    if (!Directory.Exists(exeFolder))
134→                        Directory.CreateDirectory(exeFolder);
135→
136→                    string targetPath = Path.Combine(exeFolder, fileName);
137→
138→                    // 기존 파일 백업
139→                    if (File.Exists(targetPath))
140→                    {
141→                        string bakPath = targetPath + ".bak";
142→                        if (File.Exists(bakPath)) File.Delete(bakPath);
143→                        File.Move(targetPath, bakPath);
144→                        Log($"백업 생성: {Path.GetFileName(bakPath)}");
145→                    }
146→
147→                    // 이전 버전 파일 정리 (날짜가 다른 exe)
148→                    CleanOldExes(exeFolder, fileName);
149→
150→                    // 새 파일 배치
151→                    File.Move(tempPath, targetPath);
152→                    Log($"파일 교체 완료: {targetPath}");
153→
154→                    // 7. 프로세스 재시작
155→                    Process.Start(new ProcessStartInfo
156→                    {
157→                        FileName = targetPath,
158→                        WorkingDirectory = exeFolder,
159→                        UseShellExecute = true
160→                    });
161→                    Log($"프로그램 재실행: {fileName}");
162→
163→                    IsUpdating = false;
164→                    await SendResponse(stream, true, "업데이트 완료");
165→                    OnStatusChanged?.Invoke("대기 중");
166→                }
167→                catch (Exception ex)
168→                {
169→                    IsUpdating = false;
170→                    Log($"오류: {ex.Message}");
171→                    OnStatusChanged?.Invoke("대기 중");
172→                    try { await SendResponse(stream, false, ex.Message); } catch { }
173→                }
174→            }
175→        }
176→
177→        /// <summary>설정된 패턴으로 실행 중인 프로세스 종료</summary>
178→        private void KillTargetProcess()
179→        {
180→            if (string.IsNullOrEmpty(_config.TargetProcessPattern)) return;
181→
182→            var processes = Process.GetProcesses();
183→            foreach (var proc in processes)
184→            {
185→                try
186→                {
187→                    if (proc.ProcessName.StartsWith(_config.TargetProcessPattern,
188→                        StringComparison.OrdinalIgnoreCase))
189→                    {
190→                        Log($"프로세스 종료: {proc.ProcessName} (PID: {proc.Id})");
191→                        proc.Kill();
192→                        proc.WaitForExit(5000);
193→                    }
194→                }
195→                catch { }
196→                finally { proc.Dispose(); }
197→            }
198→
199→            // 파일 잠금 해제 대기
200→            Thread.Sleep(1000);
201→        }
202→
203→        /// <summary>이전 버전 exe 파일 정리</summary>
204→        private void CleanOldExes(string folder, string newFileName)
205→        {
206→            if (string.IsNullOrEmpty(_config.TargetProcessPattern)) return;
207→
208→            try
209→            {
210→                var dir = new DirectoryInfo(folder);
211→                foreach (var file in dir.GetFiles($"{_config.TargetProcessPattern}*.exe"))
212→                {
213→                    if (!file.Name.Equals(newFileName, StringComparison.OrdinalIgnoreCase))
214→                    {
215→                        file.Delete();
216→                        Log($"이전 버전 삭제: {file.Name}");
217→                    }
218→                }
219→            }
220→            catch (Exception ex)
221→            {
222→                Log($"이전 버전 정리 실패: {ex.Message}");
223→            }
224→        }
225→
226→        /// <summary>응답 전송</summary>
227→        private static async Task SendResponse(NetworkStream stream, bool success, string message)
228→        {
229→            await stream.WriteAsync(MAGIC_RES);
230→            stream.WriteByte((byte)(success ? 0x00 : 0x01));
231→            var msgBytes = Encoding.UTF8.GetBytes(message);
232→            await stream.WriteAsync(BitConverter.GetBytes(msgBytes.Length));
233→            await stream.WriteAsync(msgBytes);
234→            await stream.FlushAsync();
235→        }
236→
237→        /// <summary>정확한 바이트 수 읽기</summary>
238→        private static async Task<byte[]> ReadExact(NetworkStream stream, int count)
239→        {
240→            var buffer = new byte[count];
241→            int offset = 0;
242→            while (offset < count)
243→            {
244→                int read = await stream.ReadAsync(buffer, offset, count - offset);
245→                if (read == 0) throw new IOException("연결 끊김");
246→                offset += read;
247→            }
248→            return buffer;
249→        }
250→
251→        private void Log(string message)
252→        {
253→            OnLog?.Invoke(message);
254→        }
255→    }
256→}
