26→        public static ServerConfig Load()
27→        {
28→            if (!File.Exists(ConfigPath))
29→            {
30→                var config = CreateDefault();
31→                config.Save();
32→                return config;
33→            }
34→            var json = File.ReadAllText(ConfigPath);
35→            return JsonSerializer.Deserialize<ServerConfig>(json) ?? CreateDefault();
36→        }
