 48→        /// <summary>그리드 셀 클릭 - exe 컬럼이면 파일 다이얼로그</summary>
 49→        private void dgvStations_CellClick(object sender, DataGridViewCellEventArgs e)
 50→        {
 51→            if (e.RowIndex < 0) return;
 52→            if (e.ColumnIndex != dgvStations.Columns["colExePath"].Index) return;
