 97→        /// <summary>선택된 스테이션에 전송</summary>
 98→        private async void btnSend_Click(object sender, EventArgs e)
 99→        {
100→            if (_sending)
101→            {
102→                MessageBox.Show("전송 중입니다. 완료 후 다시 시도하세요.", "알림",
103→                    MessageBoxButtons.OK, MessageBoxIcon.Information);
104→                return;
105→            }
106→
107→            // 선택된 스테이션 중 exe 파일이 유효한 것만 필터
108→            var selectedRows = dgvStations.Rows.Cast<DataGridViewRow>()
109→                .Where(r => Convert.ToBoolean(r.Cells["colSelect"].Value))
110→                .ToList();
111→
112→            if (selectedRows.Count == 0)
113→            {
114→                MessageBox.Show("전송 대상 스테이션을 선택하세요.", "알림",
115→                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
116→                return;
117→            }
118→
119→            // exe 파일 유효성 검사
120→            var invalidRows = selectedRows.Where(r =>
121→            {
122→                var st = r.Tag as StationInfo;
123→                return st == null || string.IsNullOrEmpty(st.ExePath) || !File.Exists(st.ExePath);
124→            }).ToList();
125→
126→            if (invalidRows.Count > 0)
127→            {
128→                var names = string.Join(", ", invalidRows.Select(r => r.Cells["colName"].Value));
129→                MessageBox.Show($"다음 스테이션의 exe 파일이 지정되지 않았거나 존재하지 않습니다:\n{names}",
130→                    "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
131→                return;
132→            }
133→
134→            // 전송 확인
135→            var stationList = string.Join("\n", selectedRows.Select(r =>
136→            {
137→                var st = r.Tag as StationInfo;
138→                return $"  {st!.Name} → {Path.GetFileName(st.ExePath)}";
139→            }));
140→            var result = MessageBox.Show(
141→                $"다음 스테이션에 전송하시겠습니까?\n\n{stationList}",
142→                "전송 확인", MessageBoxButtons.YesNo, MessageBoxIcon.Question);
143→
144→            if (result != DialogResult.Yes) return;
145→
146→            _sending = true;
147→            btnSend.Enabled = false;
148→            btnSend.Text = "전송 중...";
149→
150→            AppendLog($"=== 전송 시작: {selectedRows.Count}개 스테이션 ===");
151→
152→            // 선택된 스테이션에 병렬 전송
153→            var tasks = selectedRows.Select(row => SendToStation(row)).ToArray();
154→            await Task.WhenAll(tasks);
155→
156→            // 결과 요약
157→            int success = selectedRows.Count(r => r.Cells["colStatus"].Value?.ToString() == "완료");
158→            int fail = selectedRows.Count - success;
159→            AppendLog($"=== 전송 완료: 성공 {success}, 실패 {fail} ===");
160→
161→            _sending = false;
162→            btnSend.Enabled = true;
163→            btnSend.Text = "전송";
164→        }
165→
166→        /// <summary>단일 스테이션에 파일 전송</summary>
167→        private async Task SendToStation(DataGridViewRow row)
168→        {
169→            var station = row.Tag as StationInfo;
170→            if (station == null) return;
171→
172→            SetRowStatus(row, "전송 중...", Color.Orange);
173→            AppendLog($"[{station.Name}] {station.IP}:{station.Port} → {Path.GetFileName(station.ExePath)}");
174→
175→            var result = await FileSender.SendFileAsync(station.IP, station.Port, station.ExePath,
176→                (sent, total) =>
177→                {
178→                    int pct = (int)(sent * 100 / total);
179→                    SetRowStatus(row, $"전송 중... {pct}%", Color.Orange);
180→                });
181→
182→            if (result.Success)
183→            {
184→                SetRowStatus(row, "완료", Color.Green);
185→                AppendLog($"[{station.Name}] 성공: {result.Message}");
186→            }
187→            else
188→            {
189→                SetRowStatus(row, $"실패: {result.Message}", Color.Red);
190→                AppendLog($"[{station.Name}] 실패: {result.Message}");
191→            }
192→        }
193→
194→        /// <summary>그리드 행 상태 업데이트 (UI 스레드 안전)</summary>
195→        private void SetRowStatus(DataGridViewRow row, string status, Color color)
196→        {
197→            if (dgvStations.InvokeRequired)
198→            {
199→                dgvStations.Invoke(() => SetRowStatus(row, status, color));
200→                return;
201→            }
202→            row.Cells["colStatus"].Value = status;
203→            row.Cells["colStatus"].Style.ForeColor = color;
204→        }
205→
206→        /// <summary>로그 추가 (UI 스레드 안전)</summary>
207→        private void AppendLog(string msg)
208→        {
209→            if (txtLog.InvokeRequired)
210→            {
211→                txtLog.Invoke(() => AppendLog(msg));
212→                return;
213→            }
214→            txtLog.AppendText($"[{DateTime.Now:HH:mm:ss}] {msg}\r\n");
215→        }
216→    }
