  1→using System;
  2→using System.IO;
  3→using System.Net.Sockets;
  4→using System.Text;
  5→using System.Threading.Tasks;
  6→
  7→namespace Updater_Server
  8→{
  9→    public class SendResult
 10→    {
 11→        public bool Success { get; set; }
 12→        public string Message { get; set; } = "";
 13→    }
 14→
 15→    public static class FileSender
 16→    {
 17→        // 프로토콜 매직 바이트
 18→        private static readonly byte[] MAGIC_REQ = Encoding.ASCII.GetBytes("NXUP");
 19→        private static readonly byte[] MAGIC_RES = Encoding.ASCII.GetBytes("NXRS");
 20→
 21→        /// <summary>파일을 에이전트로 전송</summary>
 22→        public static async Task<SendResult> SendFileAsync(string ip, int port, string filePath,
 23→            Action<long, long>? onProgress = null)
 24→        {
 25→            try
 26→            {
 27→                using var client = new TcpClient();
 28→                client.SendTimeout = 30000;
 29→                client.ReceiveTimeout = 60000;
 30→
 31→                // 연결 (3초 타임아웃)
 32→                var connectTask = client.ConnectAsync(ip, port);
 33→                if (await Task.WhenAny(connectTask, Task.Delay(3000)) != connectTask)
 34→                    return new SendResult { Success = false, Message = "연결 타임아웃" };
 35→
 36→                if (connectTask.IsFaulted)
 37→                    return new SendResult { Success = false, Message = connectTask.Exception?.InnerException?.Message ?? "연결 실패" };
 38→
 39→                var stream = client.GetStream();
 40→                var fileInfo = new FileInfo(filePath);
 41→                string fileName = fileInfo.Name;
 42→                long fileSize = fileInfo.Length;
 43→
 44→                // 1. 매직 바이트
 45→                await stream.WriteAsync(MAGIC_REQ);
 46→
 47→                // 2. 파일명
 48→                var fnBytes = Encoding.UTF8.GetBytes(fileName);
 49→                await stream.WriteAsync(BitConverter.GetBytes(fnBytes.Length));
 50→                await stream.WriteAsync(fnBytes);
 51→
 52→                // 3. 파일 크기
 53→                await stream.WriteAsync(BitConverter.GetBytes(fileSize));
 54→
 55→                // 4. 파일 데이터
 56→                using (var fs = File.OpenRead(filePath))
 57→                {
 58→                    var buffer = new byte[65536];
 59→                    long sent = 0;
 60→                    int read;
 61→                    while ((read = await fs.ReadAsync(buffer, 0, buffer.Length)) > 0)
 62→                    {
 63→                        await stream.WriteAsync(buffer, 0, read);
 64→                        sent += read;
 65→                        onProgress?.Invoke(sent, fileSize);
 66→                    }
 67→                }
 68→                await stream.FlushAsync();
 69→
 70→                // 5. 응답 수신
 71→                var resMagic = await ReadExact(stream, 4);
 72→                if (!resMagic.AsSpan().SequenceEqual(MAGIC_RES))
 73→                    return new SendResult { Success = false, Message = "잘못된 응답" };
 74→
 75→                int status = stream.ReadByte();
 76→                var msgLenBuf = await ReadExact(stream, 4);
 77→                int msgLen = BitConverter.ToInt32(msgLenBuf, 0);
 78→                var msgBuf = await ReadExact(stream, msgLen);
 79→                string message = Encoding.UTF8.GetString(msgBuf);
 80→
 81→                return new SendResult
 82→                {
 83→                    Success = status == 0x00,
 84→                    Message = message
 85→                };
 86→            }
 87→            catch (Exception ex)
 88→            {
 89→                return new SendResult { Success = false, Message = ex.Message };
 90→            }
 91→        }
 92→
 93→        private static async Task<byte[]> ReadExact(NetworkStream stream, int count)
 94→        {
 95→            var buffer = new byte[count];
 96→            int offset = 0;
 97→            while (offset < count)
 98→            {
 99→                int read = await stream.ReadAsync(buffer, offset, count - offset);
100→                if (read == 0) throw new IOException("연결 끊김");
101→                offset += read;
102→            }
103→            return buffer;
104→        }
105→    }
106→}
